set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="图生图 + 局部重绘修图（I2I + inpaint/outpaint + 修脸换脸）(Decay risk: medium) last_updated: 2026-06-22"

usage() {
  cat <<EOF
i2i-inpaint-outpaint-decay-risk-.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./i2i-inpaint-outpaint-decay-risk-.sh             # interactive
  ./i2i-inpaint-outpaint-decay-risk-.sh --dry-run
  ./i2i-inpaint-outpaint-decay-risk-.sh --json
  ./i2i-inpaint-outpaint-decay-risk-.sh --explain
  ./i2i-inpaint-outpaint-decay-risk-.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "图生图 + 局部重绘修图（I2I + inpaint/outpaint + 修脸换脸）(Decay risk: medium) last_updated: 2026-06-22" 工作流。

一句话: 在已有图上做局部修复/扩展/换脸 —— 用 denoise 幅度控制改动强度，inpaint 修局部、outpaint 扩画布、Face Detailer/换脸修脸、放大超分收尾。从「一张有瑕疵的图」到「修好的成图」。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**载入原图 + 涂蒙版**：Load Image，在要改的区域涂 mask（手/脸/要替换的物体）。(evidence: [T03-S002])"
  "**选模式与 denoise**：inpaint 改局部（建议用专用 inpaint 底模），denoise 控改动幅度 —— 小（0.3-0.5）只微调、大（0.7-1.0）几乎重画。(evidence: [T03-S002])"
  "**写局部 prompt 出图**：针对蒙版区域写 prompt，跑出几版挑最融合的。"
  "**修脸**：远景/小脸糊用 Face Detailer（Impact Pack，自动裁脸放大重绘再贴回）；要替换成指定脸用 ReActor 换脸。"
  "**outpaint 扩画幅**（如需）：用 Pad Image for Outpainting 节点向外扩，再 inpaint 填补。(evidence: [T03-S020])"
  "**放大超分交付**（同 workflow 1 收尾）。"
)
declare -a FAILURE_MODES=(
  "**denoise 一刀切**：所有 inpaint 都用 1.0，微调也整块重画 —— 微调用 0.3-0.5、去物体/重画用 0.7-1.0，按改动幅度配 denoise。"
  "**不用专用 inpaint 模型**：拿普通 checkpoint 做 inpaint 接缝生硬 —— 用 base 名 + inpainting 的专用模型或 Flux Fill。"
  "**小脸不修直接交付**：群像/远景人脸糊 —— 出图链固定接 Face Detailer 自动裁脸重绘。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "i2i-inpaint-outpaint-decay-risk--walkthrough"
fi
